import java.util.Scanner;

public class SecureBufferInput {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String userInput = scanner.nextLine();

        // Limiting input length to prevent buffer overflow
        int maxLength = 10;
        if(userInput.length() > maxLength) {
            userInput = userInput.substring(0, maxLength);
        }

        // Using a StringBuilder to handle input safely
        StringBuilder safeBuffer = new StringBuilder();
        safeBuffer.append(userInput);

        System.out.println("Buffer contents: " + safeBuffer.toString());

        scanner.close();
    }
}

